INSERT INTO `answers` VALUES (115, 6, 2, 'ref和reactive的主要区别：\n\n1. ref适用于基本类型（String、Number等），reactive适用于对象和数组\n2. ref需要通过.value访问，但模板中会自动解包\n3. reactive使用Proxy实现，直接修改属性即可触发响应\n4. ref可以接收对象，内部会自动转换为reactive\n\n推荐：基本类型用ref，对象数组用reactive，或者全部用ref也可以。', 0, 12, '2026-03-21 19:30:00', '2026-03-21 19:30:00');
INSERT INTO `answers` VALUES (116, 6, 3, '补充一点，从Vue3.3开始，reactive解构会丢失响应式，但ref不会。所以如果要在setup中解构使用，推荐用toRefs包装。', 0, 8, '2026-03-21 19:45:00', '2026-03-21 19:45:00');
INSERT INTO `answers` VALUES (117, 6, 7, '我的经验是：小型项目用ref足够了，复杂项目用reactive更清晰。两者本质都是通过Proxy实现的。', 0, 5, '2026-03-21 20:00:00', '2026-03-21 20:00:00');
INSERT INTO `answers` VALUES (118, 7, 3, 'Pandas读取大文件的几种优化方法：\n\n1. 指定dtype，避免自动推断类型\n2. 使用chunksize分块读取\n3. 使用usecols只读取需要的列\n4. 将CSV转为Parquet格式，读取速度快10倍\n5. 使用polars库替代pandas，内存效率更高', 0, 18, '2026-03-21 18:30:00', '2026-03-21 18:30:00');
INSERT INTO `answers` VALUES (119, 9, 3, '深色模式实现方案：\n\n1. CSS变量 + prefers-color-scheme媒体查询（推荐）\n2. 使用class=\"dark\"切换，JS控制\n3. Tailwind CSS内置darkMode配置\n4. 使用CSS Filter: invert(1)实现快速深色（但效果一般）\n\n推荐第一种，纯CSS实现，浏览器原生支持。', 0, 15, '2026-03-19 16:00:00', '2026-03-19 16:00:00');
INSERT INTO `answers` VALUES (120, 9, 4, '补充：需要处理图片的深色模式，可以用filter: brightness(0.9)调节。图标如果是SVG，可以单独处理fill颜色。', 0, 7, '2026-03-19 18:00:00', '2026-03-19 18:00:00');
INSERT INTO `answers` VALUES (121, 10, 3, 'MySQL慢查询优化思路：\n\n1. EXPLAIN分析执行计划，关注type、key、rows字段\n2. 给WHERE条件列和ORDER BY列建索引\n3. 避免SELECT *，只查需要的字段\n4. 分页用游标分页代替OFFSET\n5. 适当使用覆盖索引\n6. 考虑数据量是否适合分库分表', 1, 32, '2026-03-18 12:00:00', '2026-03-18 12:00:00');
INSERT INTO `answers` VALUES (122, 10, 7, '补充：可以用pt-query-digest工具分析慢查询日志，找出Top N慢查询，然后针对性优化。', 0, 12, '2026-03-18 15:00:00', '2026-03-18 15:00:00');
INSERT INTO `answers` VALUES (123, 10, 4, '线上优化经验：有时候慢查询不是因为缺索引，而是因为统计信息过期，试试ANALYZE TABLE更新统计信息。', 0, 9, '2026-03-18 22:00:00', '2026-03-18 22:00:00');
