INSERT INTO `assignment_submissions` VALUES (1, 1, 1, '# HTML5页面结构设计作业\n\n我按照要求完成了页面结构设计，使用了HTML5语义化标签，包括header, nav, main, article, section, aside和footer等。\n\n## 实现要点\n\n1. 使用header标签包含网站标题和主导航\n2. 使用main标签包含页面主要内容\n3. 使用article和section组织内容区块\n4. 使用aside实现侧边栏\n5. 使用footer包含版权信息和次要导航\n\n代码已附在提交文件中。', 92, '很好的完成了作业要求，HTML结构清晰，语义化标签使用恰当。有几点小建议：1. 可以在nav中使用ul/li结构组织导航项；2. 可以为section添加更多的语义化id或class。继续保持！', '2023-06-28 15:30:45', '2023-07-01 10:15:22');
INSERT INTO `assignment_submissions` VALUES (2, 1, 2, '# HTML5页面结构设计\n\n我完成了HTML5页面结构的设计，严格按照设计稿实现，并使用了语义化标签。\n\n## 结构说明\n\n- header: 包含logo和主导航\n- main: 主内容区\n  - section: 产品介绍\n  - section: 特色功能\n  - section: 用户评价\n- aside: 侧边栏，包含相关链接和广告\n- footer: 页脚信息\n\n所有代码已通过W3C验证。', 95, '出色的工作！代码结构清晰，语义化标签使用准确，页面结构与设计稿高度一致。特别赞赏你对W3C标准的重视。一个小建议：可以考虑添加ARIA属性以提高可访问性。', '2023-06-29 09:45:12', '2023-07-01 11:20:35');
INSERT INTO `assignment_submissions` VALUES (3, 2, 1, '# CSS3响应式布局实现\n\n我使用CSS3媒体查询和Flexbox实现了响应式布局，在不同设备上都能良好展示。\n\n## 实现技术\n\n1. 使用Flexbox进行整体布局\n2. 媒体查询断点设置：\n   - 手机：<768px\n   - 平板：768px-1024px\n   - 桌面：>1024px\n3. 使用相对单位(rem, %)确保布局灵活性\n\n已提交HTML、CSS文件和各设备测试截图。', 88, '响应式布局实现得很好，断点设置合理，Flexbox使用恰当。有两点需要改进：1. 在小屏幕上导航菜单可以考虑使用汉堡菜单；2. 部分图片在小屏幕上没有等比例缩放。请在下次作业中注意这些细节。', '2023-07-12 16:40:23', '2023-07-16 14:30:18');
INSERT INTO `assignment_submissions` VALUES (4, 3, 2, '# JavaScript闭包与模块模式\n\n我实现了一个计数器模块，使用闭包实现了私有变量，并提供了增加、减少、重置和获取当前值的方法。\n\n## 代码实现\n\n```javascript\nconst createCounter = () => {\n  let count = 0;\n  \n  return {\n    increment: () => ++count,\n    decrement: () => --count,\n    reset: () => { count = 0; return count; },\n    getValue: () => count\n  };\n};\n```\n\n测试用例和结果已在提交文件中。', 98, '优秀的实现！代码简洁清晰，完美展示了闭包的应用。闭包的私有性保护得很好，接口设计合理。特别欣赏你的测试用例设计，覆盖了各种使用场景。继续保持这样的高质量代码风格！', '2023-06-24 11:25:38', '2023-06-26 09:10:45');
INSERT INTO `assignment_submissions` VALUES (5, 4, 5, '# Vue.js购物车组件\n\n我开发了一个Vue.js购物车组件，实现了所有要求的功能。\n\n## 组件结构\n\n- ShoppingCart (主组件)\n  - ProductList (商品列表组件)\n  - CartList (购物车列表组件)\n  - CartSummary (汇总组件)\n\n## 功能实现\n\n1. 使用Vuex管理购物车状态\n2. 实现了商品添加、数量修改、删除功能\n3. 使用计算属性计算总价和商品总数\n4. 实现了本地存储，刷新页面不丢失购物车数据\n\n代码和演示截图已提交。', NULL, NULL, '2023-07-09 20:15:33', NULL);
INSERT INTO `assignment_submissions` VALUES (11, 4, 6, '# Python数据分析报告\n\n使用Pandas处理销售数据集，完成数据清洗、转换、分析和可视化。\n\n分析报告包含：销售趋势、产品类别分析、客户群体分析。\n\nPython代码和PDF报告已提交。', NULL, NULL, '2026-03-21 19:30:00', NULL);
INSERT INTO `assignment_submissions` VALUES (12, 5, 9, '# Java企业级应用开发作业\n\n使用Spring Boot + MyBatis实现用户管理模块。\n\n包含：用户CRUD、分页查询、条件筛选、异常处理。\n\n代码已提交。', 90, '很好的实现！代码结构清晰，注解使用规范。建议后续加上事务管理和缓存优化。', '2026-03-20 16:00:00', '2026-03-21 10:00:00');
INSERT INTO `assignments` VALUES (1, 'HTML5页面结构设计', '根据提供的设计稿，使用HTML5语义化标签创建页面结构，包含头部、导航、主内容区、侧边栏和底部。', 1, '2023-06-30 23:59:59', 100, '# 作业要求\n\n1. 使用HTML5语义化标签（header, nav, main, article, section, aside, footer等）\n2. 页面结构需符合设计稿\n3. 代码需符合W3C规范\n4. 提交HTML文件和说明文档\n\n# 设计稿\n请参考附件中的设计稿图片。', '2025-11-21 13:45:30', '2025-11-21 13:45:30', NULL);
INSERT INTO `assignments` VALUES (2, 'CSS3响应式布局实现', '使用CSS3技术实现一个响应式网页，要求在不同设备上（手机、平板、电脑）都能良好展示。', 1, '2023-07-15 23:59:59', 100, '# 作业要求\n\n1. 使用CSS3媒体查询实现响应式布局\n2. 使用Flexbox或Grid布局技术\n3. 断点设置合理（至少包含手机、平板、桌面三种视图）\n4. 提交HTML、CSS文件和测试截图\n\n# 参考设计\n请参考附件中的设计图片。', '2025-11-21 13:45:30', '2025-11-21 13:45:30', NULL);
INSERT INTO `assignments` VALUES (3, 'JavaScript闭包与模块模式', '实现一个计数器模块，使用闭包实现私有变量，提供增加、减少、重置和获取当前值的方法。', 2, '2023-06-25 23:59:59', 100, '# 作业要求\n\n1. 使用闭包实现私有变量\n2. 提供四个公共方法：increment(), decrement(), reset(), getValue()\n3. 模块可以创建多个独立的计数器实例\n4. 提交JavaScript文件和测试用例\n\n# 示例代码结构\n```javascript\nconst createCounter = () => {\n  // 你的实现\n};\n\nconst counter1 = createCounter();\nconst counter2 = createCounter();\n// 测试代码\n```', '2025-11-21 13:45:30', '2025-11-21 13:45:30', NULL);
INSERT INTO `assignments` VALUES (4, 'Vue.js组件开发', '开发一个Vue.js购物车组件，实现商品列表展示、添加商品、修改数量、删除商品和计算总价的功能。', 3, '2023-07-10 23:59:59', 100, '# 作业要求\n\n1. 使用Vue.js组件化开发\n2. 实现商品列表展示、添加商品、修改数量、删除商品功能\n3. 使用计算属性计算总价\n4. 使用合适的事件处理机制\n5. 提交Vue组件代码和演示截图\n\n# 组件结构\n- ShoppingCart（主组件）\n  - ProductList（商品列表）\n  - CartList（购物车列表）\n  - CartSummary（购物车汇总）', '2025-11-21 13:45:30', '2025-11-21 13:45:30', NULL);
INSERT INTO `assignments` VALUES (5, 'Python数据分析报告', '使用Python对提供的销售数据集进行分析，生成销售趋势、产品类别分析和客户群体分析报告。', 4, '2023-07-20 23:59:59', 100, '# 作业要求\n\n1. 使用Pandas进行数据清洗和处理\n2. 使用Matplotlib或Seaborn进行数据可视化\n3. 分析内容包括：销售趋势、产品类别分析、客户群体分析\n4. 提交Python代码、数据分析报告（PDF格式）\n\n# 数据集\n请使用课程提供的sales_data.csv文件。', '2025-11-21 13:45:30', '2025-11-21 13:45:30', NULL);
