INSERT INTO `courses` VALUES (1, 'HTML5+CSS3零基础入门到精通', '本课程从零开始，详细讲解HTML5和CSS3的基础知识和高级应用，通过实战项目帮助学员掌握前端开发的核心技能。适合零基础学员和需要提升技能的前端开发者。', '/covers/html-css.jpg', 99.00, 7, '初级', 1800, 3, 'published', 1250, '2025-11-21 13:45:30', '2025-11-21 13:45:30');
INSERT INTO `courses` VALUES (2, 'JavaScript高级程序设计', '深入学习JavaScript语言精髓，掌握ES6+新特性，理解闭包、原型链、异步编程等核心概念，提升前端开发能力。', '/covers/javascript.jpg', 129.00, 7, '中级', 2400, 3, 'published', 980, '2025-11-21 13:45:30', '2025-11-21 13:45:30');
INSERT INTO `courses` VALUES (3, 'Vue.js实战项目开发', '基于Vue.js框架的实战课程，从组件化思想到Vuex状态管理，从路由配置到项目优化，全方位讲解Vue开发技巧。', '/covers/vuejs.jpg', 159.00, 7, '中级', 2100, 7, 'published', 865, '2025-11-21 13:45:30', '2025-11-21 13:45:30');
INSERT INTO `courses` VALUES (4, 'Python数据分析与可视化', '使用Python进行数据分析和可视化的实用课程，涵盖NumPy、Pandas、Matplotlib等库的使用，以及数据清洗、转换、分析和可视化的完整流程。', '/covers/python-data.jpg', 199.00, 10, '中级', 2700, 7, 'published', 723, '2025-11-21 13:45:30', '2025-11-21 13:45:30');
INSERT INTO `courses` VALUES (5, 'Java企业级应用开发', '从Java基础到企业级应用开发，包括Spring Boot、Spring Cloud、MyBatis等框架的使用，数据库设计与优化，以及微服务架构的实践。', '/covers/java.jpg', 249.00, 8, '高级', 3600, 3, 'published', 542, '2025-11-21 13:45:30', '2025-11-21 13:45:30');
INSERT INTO `courses` VALUES (6, 'UI设计入门到精通', '系统学习UI设计原则、色彩搭配、字体排版、图标设计等内容，掌握Sketch、Figma等主流设计工具，提升产品设计能力。', '/covers/ui-design.jpg', 149.00, 11, '初级', 2100, 4, 'published', 1105, '2025-11-21 13:45:30', '2025-11-21 13:45:30');
INSERT INTO `courses` VALUES (7, '商业插画设计实战', '学习商业插画设计的核心技法，包括人物角色、场景、构图等，掌握Procreate、Photoshop等工具的使用技巧，提升插画创作能力。', '/covers/illustration.jpg', 179.00, 12, '中级', 2400, 4, 'published', 658, '2025-11-21 13:45:30', '2025-11-21 13:45:30');
INSERT INTO `courses` VALUES (8, '新概念英语精讲', '系统讲解新概念英语教程，从发音、词汇到语法、阅读，全方位提升英语能力，适合英语学习者和备考人群。', '/covers/english.jpg', 129.00, 14, '初级', 3000, 7, 'published', 1560, '2025-11-21 13:45:30', '2025-11-21 13:45:30');
INSERT INTO `courses` VALUES (9, '日语N2备考指南', '针对日语能力考试N2级别的系统备考课程，包括词汇、语法、听力、阅读等全方位训练，助你一次通过N2考试。', '/covers/japanese.jpg', 159.00, 15, '中级', 2700, 4, 'published', 432, '2025-11-21 13:45:30', '2025-11-21 13:45:30');
INSERT INTO `courses` VALUES (10, '项目管理PMP认证课程', '系统讲解项目管理知识体系(PMBOK)，结合实际案例分析，帮助学员掌握项目管理方法论，顺利通过PMP认证考试。', '/covers/pmp.jpg', 299.00, 17, '高级', 3600, 3, 'published', 378, '2025-11-21 13:45:30', '2025-11-21 13:45:30');
