INSERT INTO `questions` VALUES (1, 'Vue组件之间如何进行通信？', '我在学习Vue.js课程时，对于父子组件、兄弟组件之间的通信方式有些混淆，特别是Vuex和事件总线的使用场景，希望能有详细解答。', 1, 3, 156, 3, '2025-11-21 13:45:30', '2025-11-21 13:45:30', NULL);
INSERT INTO `questions` VALUES (2, 'JavaScript中的闭包是什么？', '在学习JavaScript高级程序设计时，对闭包的概念理解不清晰，特别是它与作用域的关系，以及在实际开发中的应用场景，希望能有详细解释。', 2, 2, 245, 4, '2025-11-21 13:45:30', '2025-11-21 13:45:30', NULL);
INSERT INTO `questions` VALUES (3, 'CSS Grid和Flexbox有什么区别？', '在学习响应式布局时，不太理解CSS Grid和Flexbox的适用场景和区别，希望能有具体的实例说明。', 5, 1, 189, 2, '2025-11-21 13:45:30', '2025-11-21 13:45:30', NULL);
INSERT INTO `questions` VALUES (4, 'Python数据分析中如何处理缺失值？', '在使用Pandas进行数据分析时，遇到了大量缺失值，不知道应该采用什么策略处理，是直接删除还是填充，希望能有最佳实践分享。', 6, 4, 132, 3, '2025-11-21 13:45:30', '2025-11-21 13:45:30', NULL);
INSERT INTO `questions` VALUES (5, 'Java Spring Boot如何实现权限控制？', '在开发企业应用时，需要实现基于角色的权限控制，不太清楚Spring Security的配置方法，希望能有详细的步骤指导。', 9, 5, 178, 2, '2025-11-21 13:45:30', '2025-11-21 13:45:30', NULL);
INSERT INTO `questions` VALUES (6, 'Vue3中ref和reactive有什么区别？', '我刚学习Vue3，看到有ref和reactive两种定义响应式数据的方式，不明白它们各自的使用场景和区别，希望能有详细解答。', 1, 3, 156, 3, '2026-03-21 19:00:00', '2026-03-21 20:00:00', '2026-03-21 20:00:00');
INSERT INTO `questions` VALUES (7, 'Python中如何优化Pandas读取大文件的性能？', '工作中遇到几十GB的CSV文件，用pandas.read_csv读取特别慢，有什么好的优化方法吗？', 5, 4, 132, 1, '2026-03-21 18:00:00', '2026-03-21 19:00:00', '2026-03-21 19:00:00');
INSERT INTO `questions` VALUES (8, 'Spring Boot中如何实现接口统一参数校验？', '我想在Spring Boot中做参数校验，但每个接口都要写if判断太麻烦，有没有优雅的统一校验方式？', 9, 5, 89, 0, '2026-03-20 15:00:00', '2026-03-20 15:00:00', NULL);
INSERT INTO `questions` VALUES (9, 'CSS中如何实现深色模式（Dark Mode）？', '想给网站添加深色模式，但是不知道用什么技术方案比较合适，求推荐。', 2, 1, 178, 2, '2026-03-19 14:00:00', '2026-03-19 18:00:00', '2026-03-19 18:00:00');
INSERT INTO `questions` VALUES (10, 'MySQL中慢查询如何优化？', '发现线上有几个查询特别慢，用EXPLAIN看了但不知道怎么优化，求分析思路。', 6, 5, 245, 3, '2026-03-18 10:00:00', '2026-03-18 22:00:00', '2026-03-18 22:00:00');
